tasks.script:
$data = @(
  [PSCustomObject]@{Name='Alice'; Age=30; City='NYC'},
  [PSCustomObject]@{Name='Bob'; Age=25; City='LA'},
  [PSCustomObject]@{Name='Charlie'; Age=35; City='SF'}
); $data | Export-Csv -Path '.\people.csv' -NoTypeInformation; Write-Host 'CSV created with 3 records'

try {
  $content = Get-Content -Path 'nonexistent-file.txt' -ErrorAction Stop
  Write-Host 'File found'
} catch {
  Write-Host 'Error handled: File not found'
}

function Get-Prime {
  param([int]$n)
  if ($n -lt 2) {return $false}
  for ($i = 2; $i -le [math]::Sqrt($n); $i++) {
    if ($n % $i -eq 0) {return $false}
  }
  return $true
}
$primes = 1..20 | Where-Object {Get-Prime $_}; Write-Host "Primes: $($primes -join ', ')"

$text = 'Contact us at support@example.com or sales@company.org';
$emails = [regex]::Matches($text, '[\w.-]+@[\w.-]+\.[\w]+') | ForEach-Object {$_.Value};
Write-Host "Found emails: $($emails -join ', ')"
